import {t} from "ftc-common/i18n";
import {Dispatch, RefObject, SetStateAction, useRef, useState} from "react";

export function delayStr(scheduledStart?: number, start?: number) {
    if(!scheduledStart || !start || start < 0) {
        return '';
    }
    const startDiff = start - scheduledStart;
    const diffMin = Math.round(Math.abs(startDiff) / 60000);

    if(diffMin === 0) {
        return t`On Time`;
    } else if(startDiff > 0) {
        return t`${diffMin}m behind`
    } else {
        return t`${diffMin}m ahead`
    }
}

// Types adapted from react
// useful when you want to track something with state but also want to be able to access the current value without rebinding callbacks
export function useStateRef<S>(initialState: S | (() => S)): [S, Dispatch<SetStateAction<S>>, RefObject<S>];
export function useStateRef<S = undefined>(): [S | undefined, Dispatch<SetStateAction<S | undefined>>, RefObject<S>];
export function useStateRef<S>(initialState?: S | (() => S)) {
    const [state, setState] = useState(initialState);
    const ref = useRef(initialState);

    function realSetState(action: SetStateAction<S>) {
        setState((prev) => {
            const newState = typeof action === 'function' ? (action as (prevState: S | undefined) => S)(prev) : action;
            ref.current = newState;
            return newState;
        });
    }

    return [state, realSetState, ref];
}